from dataclasses import dataclass, field
from datetime import date
from enum import Enum

class ActionStatus(str, Enum):
    PLANNED = "planned"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"
    DEFERRED = "deferred"

@dataclass
class CorrectiveAction:
    description: str
    owner: str
    target_date: date
    status: ActionStatus = ActionStatus.PLANNED
    completed_date: date | None = None
    jira_ticket: str | None = None

@dataclass
class IncidentFollowUp:
    incident_id: str
    pir_published: bool = False
    pir_url: str | None = None
    csm_checkin_done: bool = False
    corrective_actions: list[CorrectiveAction] = field(default_factory=list)

    def all_actions_complete(self) -> bool:
        return all(a.status == ActionStatus.COMPLETED for a in self.corrective_actions)

    def overdue_actions(self, as_of: date) -> list[CorrectiveAction]:
        return [
            a for a in self.corrective_actions
            if a.status != ActionStatus.COMPLETED and a.target_date < as_of
        ]

    def status_summary(self) -> dict:
        done = sum(1 for a in self.corrective_actions if a.status == ActionStatus.COMPLETED)
        total = len(self.corrective_actions)
        return {
            "incident_id": self.incident_id,
            "pir_published": self.pir_published,
            "actions_complete": f"{done}/{total}",
            "all_done": self.all_actions_complete(),
        }
